diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..756aecc6afbb 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -7057,6 +7057,224 @@ static bool reduceSwitchRange(SwitchInst *SI, IRBuilder<> &Builder,
   return true;
 }

+/// Try to simplify a switch on the result of a ucmp/scmp intrinsic.
+/// ucmp/scmp returns -1, 0, or 1 for <, ==, > respectively.
+/// If the switch only distinguishes between "less" vs "greater-or-equal" etc.,
+/// we can replace it with a simple icmp and branch.
+/// For example:
+///   switch(ucmp(a, b)) { case -1: case 0: A; default: B; }
+/// becomes:
+///   br icmp ugt(a, b) ? B : A
+static bool simplifySwitchOfCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder,
+                                         const DataLayout &DL,
+                                         DomTreeUpdater *DTU) {
+  Value *Cond = SI->getCondition();
+
+  // Check if the condition is a ucmp or scmp intrinsic.
+  auto *II = dyn_cast<IntrinsicInst>(Cond);
+  if (!II)
+    return false;
+
+  Intrinsic::ID IID = II->getIntrinsicID();
+  if (IID != Intrinsic::ucmp && IID != Intrinsic::scmp)
+    return false;
+
+  // We need exactly 2 distinct destinations (including default).
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  BasicBlock *DestA = nullptr;
+  BasicBlock *DestB = nullptr;
+
+  for (auto Case : SI->cases()) {
+    BasicBlock *Dest = Case.getCaseSuccessor();
+    if (Dest != DefaultDest) {
+      if (!DestA)
+        DestA = Dest;
+      else if (DestA != Dest) {
+        if (!DestB)
+          DestB = Dest;
+        else if (DestB != Dest)
+          return false; // More than 2 destinations.
+      }
+    }
+  }
+
+  // If we only have one non-default destination.
+  if (!DestA)
+    return false;
+
+  // If DestB is null, we have only one non-default destination.
+  // The default is the second destination.
+  if (!DestB)
+    DestB = DefaultDest;
+
+  assert(DestA != DestB);
+
+  // Collect which cmp results go to which destination.
+  // ucmp/scmp returns: -1 (less), 0 (equal), 1 (greater)
+  bool LessToA = false, EqualToA = false, GreaterToA = false;
+  bool LessToB = false, EqualToB = false, GreaterToB = false;
+
+  auto ProcessCase = [&](ConstantInt *Val, BasicBlock *Dest) {
+    const APInt &V = Val->getValue();
+    if (V.isAllOnes()) { // -1
+      if (Dest == DestA)
+        LessToA = true;
+      else
+        LessToB = true;
+    } else if (V.isZero()) { // 0
+      if (Dest == DestA)
+        EqualToA = true;
+      else
+        EqualToB = true;
+    } else if (V.isOne()) { // 1
+      if (Dest == DestA)
+        GreaterToA = true;
+      else
+        GreaterToB = true;
+    }
+  };
+
+  for (auto Case : SI->cases()) {
+    ProcessCase(Case.getCaseValue(), Case.getCaseSuccessor());
+  }
+
+  // Check if default destination corresponds to any specific cmp result.
+  // The default is taken when the value is not explicitly listed.
+  // ucmp/scmp can only return -1, 0, 1.
+  if (!LessToA && !LessToB)
+    ProcessCase(cast<ConstantInt>(ConstantInt::get(Cond->getType(), -1, true)), DefaultDest);
+  if (!EqualToA && !EqualToB)
+    ProcessCase(cast<ConstantInt>(ConstantInt::get(Cond->getType(), 0, true)), DefaultDest);
+  if (!GreaterToA && !GreaterToB)
+    ProcessCase(cast<ConstantInt>(ConstantInt::get(Cond->getType(), 1, true)), DefaultDest);
+
+  // Now determine what predicate we need.
+  // We need exactly one of DestA/DestB to have "less" and the other "greater-or-equal"
+  // or similar patterns that map to a single icmp.
+
+  ICmpInst::Predicate Pred;
+  BasicBlock *TrueDest, *FalseDest;
+
+  // Check for patterns that map to a single icmp.
+  // Pattern: Less goes to one dest, Equal+Greater go to the other.
+  // This is "not less" i.e., "greater or equal".
+  if (LessToA && !LessToB && EqualToB && GreaterToB && !EqualToA && !GreaterToA) {
+    // DestA = less, DestB = greater-or-equal
+    // Branch on "greater-or-equal" i.e., "not less"
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (LessToB && !LessToA && EqualToA && GreaterToA && !EqualToB && !GreaterToB) {
+    // DestB = less, DestA = greater-or-equal
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  }
+  // Pattern: Less+Equal go to one dest, Greater goes to the other.
+  // This is "not greater".
+  else if (LessToA && EqualToA && !GreaterToA && GreaterToB && !LessToB && !EqualToB) {
+    // DestA = less-or-equal, DestB = greater
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (LessToB && EqualToB && !GreaterToB && GreaterToA && !LessToA && !EqualToA) {
+    // DestB = less-or-equal, DestA = greater
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  }
+  // Pattern: Equal+Greater go to one dest, Less goes to the other.
+  // This is "not less".
+  else if (EqualToA && GreaterToA && !LessToA && LessToB && !EqualToB && !GreaterToB) {
+    // DestA = greater-or-equal, DestB = less
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (EqualToB && GreaterToB && !LessToB && LessToA && !EqualToA && !GreaterToA) {
+    // DestB = greater-or-equal, DestA = less
+    Pred = (IID == Intrinsic::scmp) ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  }
+  // Pattern: Less+Greater go to one dest, Equal goes to the other.
+  // This is "not equal".
+  else if (LessToA && GreaterToA && !EqualToA && EqualToB && !LessToB && !GreaterToB) {
+    // DestA = not-equal, DestB = equal
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (LessToB && GreaterToB && !EqualToB && EqualToA && !LessToA && !GreaterToA) {
+    // DestB = not-equal, DestA = equal
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  }
+  // Pattern: Only Less vs Greater (Equal not possible or goes to one side).
+  // This requires checking if Equal is impossible or handled.
+  else {
+    return false;
+  }
+
+  // Build the icmp and branch.
+  Builder.SetInsertPoint(SI);
+  Value *LHS = II->getOperand(0);
+  Value *RHS = II->getOperand(1);
+
+  // If the operands don't match the switch type, we may need to cast.
+  // The ucmp/scmp can have different operand types than result type.
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS, "switch.cmp");
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+
+  // Update branch weights if present.
+  if (hasBranchWeightMD(*SI)) {
+    SmallVector<uint64_t, 8> Weights;
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 1 + SI->getNumCases()) {
+      uint64_t TrueWeight = 0;
+      uint64_t FalseWeight = 0;
+      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
+        if (SI->getSuccessor(I) == TrueDest)
+          TrueWeight += Weights[I];
+        else
+          FalseWeight += Weights[I];
+      }
+      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
+        TrueWeight /= 2;
+        FalseWeight /= 2;
+      }
+      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
+    }
+  }
+
+  // Remove the switch and update PHI nodes.
+  BasicBlock *BB = SI->getParent();
+  SmallPtrSet<BasicBlock *, 4> RemovedSuccessors;
+  std::vector<DominatorTree::UpdateType> Updates;
+
+  for (unsigned i = 0, e = SI->getNumSuccessors(); i != e; ++i) {
+    BasicBlock *Succ = SI->getSuccessor(i);
+    if (Succ != TrueDest && Succ != FalseDest) {
+      Succ->removePredecessor(BB);
+      if (DTU && RemovedSuccessors.insert(Succ).second)
+        Updates.push_back({DominatorTree::Delete, BB, Succ});
+    }
+  }
+
+  SI->eraseFromParent();
+
+  // Remove the intrinsic call if it is no longer used.
+  if (II->use_empty())
+    II->eraseFromParent();
+
+  if (DTU) {
+    Updates.push_back({DominatorTree::Insert, BB, TrueDest});
+    Updates.push_back({DominatorTree::Insert, BB, FalseDest});
+    DTU->applyUpdates(Updates);
+  }
+
+  return true;
+}
+
 /// Tries to transform switch of powers of two to reduce switch range.
 /// For example, switch like:
 /// switch (C) { case 1: case 2: case 64: case 128: }
@@ -7163,6 +7381,10 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   if (eliminateDeadSwitchCases(SI, DTU, Options.AC, DL))
     return requestResimplify();

+  // Try to simplify switch on ucmp/scmp intrinsic.
+  if (simplifySwitchOfCmpIntrinsic(SI, Builder, DL, DTU))
+    return requestResimplify();
+
   if (trySwitchToSelect(SI, Builder, DTU, DL, TTI))
     return requestResimplify();

